{"code": "import json
from collections import defaultdict
import datetime

# Get the file path from storage
file_path = locals()['var_functions.query_db:36']

# Load the patent data from the file
with open(file_path, 'r') as f:
    patents_data = json.load(f)

print('Loaded', len(patents_data), 'German patents from second half of 2019')

# Process CPC codes
cpc_counts = defaultdict(int)

for patent in patents_data:
    cpc_field = patent.get('cpc', '[]')
    if cpc_field:
        try:
            cpc_list = json.loads(cpc_field)
            for cpc_item in cpc_list:
                code = cpc_item.get('code', '')
                if code and '/' in code:
                    parts = code.split('/')
                    if len(parts) == 2:
                        level4_code = parts[0]
                        cpc_counts[level4_code] += 1
        except Exception as e:
            continue

print('Found', len(cpc_counts), 'CPC level 4 groups')

cpc_list = sorted(cpc_counts.items(), key=lambda x: x[1], reverse=True)
result = {
    'cpc_groups': cpc_list[:10],
    'total_cpc_groups': len(cpc_counts)
}
print('__RESULT__:')
print(json.dumps(result))"}

